import type {
  AttemptListItem,
  AttemptSummary,
  ChatMessage,
  DocumentDetail,
  DocumentSummary,
  Plan,
  QuizDTO,
} from "./types";

const BASE = "http://localhost:3003";

export class ApiError extends Error {
  status: number;
  constructor(message: string, status: number) {
    super(message);
    this.status = status;
  }
}

async function jsonFetch<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    headers: { "Content-Type": "application/json" },
    ...init,
  });
  if (!res.ok) {
    let msg = `Request failed (${res.status})`;
    try {
      const body = await res.json();
      msg = body.error ?? msg;
    } catch {
      // ignore
    }
    throw new ApiError(msg, res.status);
  }
  if (res.status === 204) return undefined as unknown as T;
  return (await res.json()) as T;
}

export async function listDocuments(): Promise<DocumentSummary[]> {
  return jsonFetch<DocumentSummary[]>("/api/documents");
}

export async function getDocument(id: number): Promise<DocumentDetail> {
  return jsonFetch<DocumentDetail>(`/api/documents/${id}`);
}

export async function uploadPdf(file: File): Promise<DocumentDetail> {
  const form = new FormData();
  form.append("file", file);
  const res = await fetch(`${BASE}/api/documents/upload`, {
    method: "POST",
    body: form,
  });
  if (!res.ok) {
    let msg = "Upload failed";
    try {
      const body = await res.json();
      msg = body.error ?? msg;
    } catch {
      // ignore
    }
    throw new ApiError(msg, res.status);
  }
  return (await res.json()) as DocumentDetail;
}

export async function listPlansForDocument(id: number): Promise<Plan[]> {
  return jsonFetch<Plan[]>(`/api/documents/${id}/plans`);
}

export async function createPlan(documentId: number): Promise<Plan> {
  return jsonFetch<Plan>(`/api/documents/${documentId}/plans`, {
    method: "POST",
    body: "{}",
  });
}

export async function getPlan(planId: number): Promise<Plan> {
  return jsonFetch<Plan>(`/api/lesson-plans/${planId}`);
}

export async function approvePlan(planId: number): Promise<Plan> {
  return jsonFetch<Plan>(`/api/lesson-plans/${planId}/approve`, {
    method: "POST",
    body: "{}",
  });
}

export async function listQuizzes(planId: number): Promise<QuizDTO[]> {
  return jsonFetch<QuizDTO[]>(`/api/lesson-plans/${planId}/quizzes`);
}

export async function generateQuiz(
  planId: number,
  objectiveIndex: number,
): Promise<QuizDTO> {
  return jsonFetch<QuizDTO>(`/api/lesson-plans/${planId}/quizzes`, {
    method: "POST",
    body: JSON.stringify({ objectiveIndex }),
  });
}

export async function getExplanation(quizId: number): Promise<{
  explanation: string;
  correctIndex: number;
}> {
  return jsonFetch(`/api/quizzes/${quizId}/explain`, { method: "POST", body: "{}" });
}

export async function checkAnswer(
  quizId: number,
  learnerIndex: number,
): Promise<{ correct: boolean; explanation?: string }> {
  return jsonFetch(`/api/quizzes/${quizId}/check`, {
    method: "POST",
    body: JSON.stringify({ learnerIndex }),
  });
}

export async function getHint(
  quizId: number,
  previousGuessIndex: number | null,
): Promise<{ hint: string }> {
  return jsonFetch(`/api/quizzes/${quizId}/hint`, {
    method: "POST",
    body: JSON.stringify({ previousGuessIndex }),
  });
}

export async function learnMore(
  quizId: number,
  learnerQuestion: string,
  history: ChatMessage[],
): Promise<{ message: string }> {
  return jsonFetch(`/api/quizzes/${quizId}/learn-more`, {
    method: "POST",
    body: JSON.stringify({
      learnerQuestion,
      history,
    }),
  });
}

export async function completeAttempt(
  planId: number,
  answers: Array<{
    quizId: number;
    learnerIndex: number | null;
    attempts: number;
  }>,
): Promise<AttemptSummary> {
  return jsonFetch(`/api/lesson-plans/${planId}/complete`, {
    method: "POST",
    body: JSON.stringify({ answers }),
  });
}

export async function listAttempts(
  planId: number,
): Promise<AttemptListItem[]> {
  return jsonFetch<AttemptListItem[]>(`/api/lesson-plans/${planId}/attempts`);
}

