import { useCallback, useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { ArrowLeft, Loader2 } from "lucide-react";
import { PlanCard } from "#components/plan-card";
import { MCQWidget } from "#components/mcq-widget";
import {
  ObjectiveTracker,
  type ObjectiveStatus,
} from "#components/objective-tracker";
import { SummaryView } from "#components/summary-view";
import { Card, CardContent } from "#components/ui/card";
import { Progress } from "#components/ui/progress";
import {
  approvePlan,
  completeAttempt,
  generateQuiz,
  getPlan,
  listQuizzes,
} from "#lib/api";
import type {
  AttemptSummary,
  Plan,
  QuizDTO,
} from "#lib/types";
import { difficultyLabel } from "#lib/format";

type Phase = "loading" | "review" | "quiz" | "summary" | "error";

interface AnswerState {
  quizId: number;
  learnerIndex: number | null;
  attempts: number;
  correct: boolean;
  finalized: boolean;
}

function blankAnswer(quizId: number): AnswerState {
  return {
    quizId,
    learnerIndex: null,
    attempts: 0,
    correct: false,
    finalized: false,
  };
}

export function LessonPage() {
  const { planId } = useParams<{ planId: string }>();
  const navigate = useNavigate();
  const [phase, setPhase] = useState<Phase>("loading");
  const [plan, setPlan] = useState<Plan | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [quizzes, setQuizzes] = useState<Record<number, QuizDTO>>({});
  const [answers, setAnswers] = useState<Record<number, AnswerState>>({});
  const [currentIdx, setCurrentIdx] = useState(0);
  const [loadingQuiz, setLoadingQuiz] = useState(false);
  const [summary, setSummary] = useState<AttemptSummary | null>(null);
  const [finishing, setFinishing] = useState(false);

  useEffect(() => {
    if (!planId) return;
    const id = Number(planId);
    getPlan(id)
      .then((p) => {
        setPlan(p);
        if (p.status === "draft") setPhase("review");
        else setPhase("quiz");
      })
      .catch((err: unknown) => {
        setError((err as Error).message);
        setPhase("error");
      });
  }, [planId]);

  // Preload cached quizzes when entering the quiz phase (retest path)
  useEffect(() => {
    if (phase !== "quiz" || !planId || !plan) return;
    const id = Number(planId);
    listQuizzes(id)
      .then((existing) => {
        if (existing.length === 0) return;
        const map: Record<number, QuizDTO> = {};
        for (const q of existing) map[q.objectiveIndex] = q;
        setQuizzes(map);
      })
      .catch(() => {
        // ignore — we'll lazy-generate
      });
  }, [phase, planId, plan]);

  const currentQuiz = quizzes[currentIdx];

  // Lazy-generate the quiz for the current objective when needed
  useEffect(() => {
    if (phase !== "quiz" || !plan || !planId) return;
    if (quizzes[currentIdx] || loadingQuiz) return;
    if (currentIdx >= plan.objectives.length) return;
    const id = Number(planId);
    setLoadingQuiz(true);
    generateQuiz(id, currentIdx)
      .then((q) => {
        setQuizzes((prev) => ({ ...prev, [currentIdx]: q }));
      })
      .catch((err: unknown) => {
        setError((err as Error).message);
        setPhase("error");
      })
      .finally(() => setLoadingQuiz(false));
  }, [phase, plan, planId, currentIdx, quizzes, loadingQuiz]);

  const handleApprove = useCallback(async () => {
    if (!plan) return;
    try {
      const updated = await approvePlan(plan.id);
      setPlan(updated);
      setPhase("quiz");
    } catch (err) {
      setError((err as Error).message);
      setPhase("error");
    }
  }, [plan]);

  const handleIncorrect = useCallback(
    (idx: number, learnerIndex: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[idx]?.id ?? -1;
        const existing = prev[idx] ?? blankAnswer(quizId);
        return {
          ...prev,
          [idx]: {
            ...existing,
            quizId,
            learnerIndex,
            correct: false,
            attempts: existing.attempts + 1,
            finalized: false,
          },
        };
      });
    },
    [quizzes],
  );

  const handleCorrect = useCallback(
    (idx: number, learnerIndex: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[idx]?.id ?? -1;
        const existing = prev[idx] ?? blankAnswer(quizId);
        return {
          ...prev,
          [idx]: {
            ...existing,
            quizId,
            learnerIndex,
            correct: true,
            // attempts stays — counts only incorrect tries
            finalized: true,
          },
        };
      });
    },
    [quizzes],
  );

  const handleSkip = useCallback(
    (idx: number) => {
      setAnswers((prev) => {
        const quizId = quizzes[idx]?.id ?? -1;
        const existing = prev[idx] ?? blankAnswer(quizId);
        return {
          ...prev,
          [idx]: {
            ...existing,
            quizId,
            learnerIndex: null,
            correct: false,
            finalized: true,
          },
        };
      });
      setCurrentIdx((i) => i + 1);
    },
    [quizzes],
  );

  const finish = useCallback(async () => {
    if (!plan || !planId || finishing) return;
    setFinishing(true);
    try {
      const payload = Object.values(answers).map((a) => ({
        quizId: a.quizId,
        learnerIndex: a.learnerIndex,
        attempts: a.attempts,
      }));
      const result = await completeAttempt(plan.id, payload);
      setSummary(result);
      setPhase("summary");
    } catch (err) {
      setError((err as Error).message);
      setPhase("error");
    } finally {
      setFinishing(false);
    }
  }, [plan, planId, answers, finishing]);

  const advance = useCallback(() => {
    if (!plan) return;
    if (currentIdx + 1 >= plan.objectives.length) {
      void finish();
    } else {
      setCurrentIdx((i) => i + 1);
    }
  }, [currentIdx, plan, finish]);

  const handleRetake = useCallback(() => {
    setAnswers({});
    setQuizzes({});
    setCurrentIdx(0);
    setSummary(null);
    setPhase("quiz");
  }, []);

  if (phase === "loading") {
    return (
      <div className="flex h-[60vh] items-center justify-center">
        <Loader2 className="size-6 animate-spin text-primary" />
      </div>
    );
  }

  if (phase === "error" || !plan) {
    return (
      <div className="mx-auto max-w-2xl">
        <Card>
          <CardContent className="p-8 text-center">
            <p className="text-sm font-medium text-danger">
              {error ?? "Something went wrong."}
            </p>
            <button
              onClick={() => navigate("/")}
              className="mt-4 inline-flex items-center gap-1.5 text-sm text-muted-foreground hover:text-foreground"
            >
              <ArrowLeft className="size-4" />
              Back to library
            </button>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (phase === "review") {
    return (
      <PlanCard
        plan={plan}
        onApprove={handleApprove}
        onBack={() => navigate("/")}
      />
    );
  }

  if (phase === "summary" && summary) {
    return (
      <SummaryView
        summary={summary}
        onRetake={handleRetake}
        onBackToLibrary={() => navigate("/")}
      />
    );
  }

  // quiz phase
  const total = plan.objectives.length;
  const answerList = plan.objectives.map((_, i) => answers[i]);
  const completed = answerList.filter((a) => a?.finalized).length;
  const score = answerList.filter((a) => a?.correct).length;
  const progressPct = total === 0 ? 0 : Math.round((completed / total) * 100);
  const statuses: ObjectiveStatus[] = plan.objectives.map((_, i) => {
    const a = answers[i];
    if (a?.finalized) {
      return a.correct ? "correct" : "skipped";
    }
    if (i === currentIdx) return "current";
    return "pending";
  });

  return (
    <div className="space-y-6">
      <button
        onClick={() => navigate("/")}
        className="inline-flex items-center gap-1.5 text-sm text-muted-foreground transition-colors hover:text-foreground"
      >
        <ArrowLeft className="size-4" />
        Back to library
      </button>

      <div className="space-y-2">
        <div className="flex items-center justify-between gap-3">
          <div className="min-w-0">
            <h1 className="truncate text-xl font-bold tracking-tight">
              {plan.title}
            </h1>
            <p className="text-xs text-muted-foreground">
              {difficultyLabel(plan.difficulty)} · {completed} of {total}{" "}
              objectives done
            </p>
          </div>
          <div className="text-right">
            <p className="text-2xl font-bold tabular-nums">
              {score}
              <span className="text-base text-muted-foreground">
                /{total}
              </span>
            </p>
          </div>
        </div>
        <Progress value={progressPct} />
      </div>

      <div className="grid gap-6 lg:grid-cols-[1fr_280px]">
        <div className="min-w-0">
          {currentQuiz ? (
            <MCQWidget
              key={currentQuiz.id}
              quiz={currentQuiz}
              objectiveNumber={currentIdx + 1}
              totalObjectives={total}
              onCorrect={(learnerIndex, explanation) => {
                void explanation;
                handleCorrect(currentIdx, learnerIndex);
              }}
              onIncorrect={(learnerIndex) =>
                handleIncorrect(currentIdx, learnerIndex)
              }
              onSkip={() => handleSkip(currentIdx)}
              onNext={advance}
              isLast={currentIdx === total - 1}
            />
          ) : (
            <Card>
              <CardContent className="flex flex-col items-center justify-center gap-3 p-12 text-center">
                <Loader2 className="size-6 animate-spin text-primary" />
                <p className="text-sm text-muted-foreground">
                  Generating question for objective {currentIdx + 1}...
                </p>
              </CardContent>
            </Card>
          )}
          {finishing && (
            <p className="mt-4 flex items-center justify-center gap-2 text-sm text-muted-foreground">
              <Loader2 className="size-4 animate-spin" />
              Building your progress report...
            </p>
          )}
        </div>

        <aside className="lg:sticky lg:top-20 lg:self-start">
          <ObjectiveTracker
            objectives={plan.objectives}
            statuses={statuses}
            score={score}
            total={total}
          />
        </aside>
      </div>
    </div>
  );
}

